   145→                createServerCallbackHandlers(configs);
   146→                createConnectionsMaxReauthMsMap(configs);
   147→            } else
   148→                createClientCallbackHandler(configs);
   149→            for (Map.Entry<String, AuthenticateCallbackHandler> entry : saslCallbackHandlers.entrySet()) {
   150→                String mechanism = entry.getKey();
   151→                entry.getValue().configure(configs, mechanism, jaasContexts.get(mechanism).configurationEntries());
   152→            }
   153→
   154→            Class<? extends Login> defaultLoginClass = defaultLoginClass();
   155→            if (connectionMode == ConnectionMode.SERVER && jaasContexts.containsKey(SaslConfigs.GSSAPI_MECHANISM)) {
   156→                String defaultRealm;
   157→                try {
   158→                    defaultRealm = defaultKerberosRealm();
   159→                } catch (Exception ke) {
   160→                    defaultRealm = "";
   161→                }
   162→                List<String> principalToLocalRules = (List<String>) configs.get(BrokerSecurityConfigs.SASL_KERBEROS_PRINCIPAL_TO_LOCAL_RULES_CONFIG);
   163→                if (principalToLocalRules != null)
   164→                    kerberosShortNamer = KerberosShortNamer.fromUnparsedRules(defaultRealm, principalToLocalRules);
   165→            }
   166→            for (Map.Entry<String, JaasContext> entry : jaasContexts.entrySet()) {
   167→                String mechanism = entry.getKey();
