   338→    private void createConnectionsMaxReauthMsMap(Map<String, ?> configs) {
   339→        for (String mechanism : jaasContexts.keySet()) {
   340→            String prefix = ListenerName.saslMechanismPrefix(mechanism);
   341→            Long connectionsMaxReauthMs = (Long) configs.get(prefix + BrokerSecurityConfigs.CONNECTIONS_MAX_REAUTH_MS_CONFIG);
   342→            if (connectionsMaxReauthMs == null)
   343→                connectionsMaxReauthMs = (Long) configs.get(BrokerSecurityConfigs.CONNECTIONS_MAX_REAUTH_MS_CONFIG);
   344→            if (connectionsMaxReauthMs != null)
   345→                connectionsMaxReauthMsByMechanism.put(mechanism, connectionsMaxReauthMs);
   346→        }
   347→    }
